module priority_encoder(IN,input_data);
input [3:0] IN;
output [1:0] input_data;
reg [1:0] input_data;

always@(IN) begin
	if (IN[3])
		input_data = 2'b11;
	else if (IN[2])
		input_data = 2'b10;
	else if (IN[1])
		input_data = 2'b01;
	else if (IN[0])
		input_data = 2'b00;
	else
		input_data = 2'b00;
end

endmodule
